mapper.select:
SELECT s.store_id, s.region_id, s.store_name, s.category, s.address, s.phone, s.business_hours, s.description, s.emoji, s.rating_avg, s.status, s.latitude, s.longitude, DATE_FORMAT(s.updated_at, '%Y%m%d%H%i%s') AS img_ver, r.region_name, (SELECT COUNT(*) FROM tb_user_coupon uc JOIN tb_coupon co ON uc.coupon_id = co.coupon_id WHERE co.store_id = s.store_id AND co.is_deleted = 0 AND uc.status = 'USED' AND uc.is_deleted = 0) AS used_count, (SELECT COUNT(*) FROM tb_review rv WHERE rv.store_id = s.store_id AND rv.status = 'ACTIVE' AND rv.is_deleted = 0) AS review_count FROM tb_store s LEFT JOIN tb_region r ON s.region_id = r.region_id WHERE s.status = 'ACTIVE' AND s.is_deleted = 0
AND s.region_id = #{regionId}
AND s.category = #{category}
ORDER BY used_count DESC, s.rating_avg DESC, s.store_id DESC LIMIT #{limit}

mapper.sql:
WHERE s.status     = 'ACTIVE'
  AND s.is_deleted = 0

      AND s.region_id = #{regionId}


      AND s.category = #{category}


      AND s.store_name LIKE CONCAT('%', #{keyword}, '%')

mapper.select:
SELECT co.coupon_id, co.store_id, co.coupon_name, co.benefit, co.condition_text, co.expire_date, co.total_count, co.issued_count, co.max_per_user, co.status, co.created_at, s.store_name FROM tb_coupon co JOIN tb_store s ON co.store_id = s.store_id WHERE co.status = 'ACTIVE' AND co.is_deleted = 0 AND s.status = 'ACTIVE' AND s.is_deleted = 0 AND co.expire_date >= CURDATE() AND (co.total_count = 0 OR co.issued_count < co.total_count)
AND s.region_id = #{regionId}
ORDER BY co.issued_count DESC, co.coupon_id DESC LIMIT #{limit}
